  ('elementary-6e11b43e-moex-00075', 'elementary-6e11b43e', 'elementary-6e11b43e-moex-114-ea33d64d', 'sub-elementary-6e11b43e-02', NULL, 'single_choice', '政府捐助之原住民族電視及廣播機構，應製作原住民族語言節目及語言學習課程，並出版原住民族語言出 版品。前項原住民族語言節目及課程使用原住民族語言之比例，不得低於該機構總時數之比例為何？', '["百分之三十", "百分之五十", "百分之六十", "百分之八十"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:55+00:00", "source_pdf_sha1": "c52cfd10ec2a", "answer_pdf_sha1": "02f86109cb69", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "504", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "原住民族行政"}'::jsonb, NULL),
